svg.script:
document.addEventListener('DOMContentLoaded', () => {
    const svg = document.getElementById('main-svg');
    const container = document.getElementById('zoom-container');

    const nodes = document.querySelectorAll('.node');
    const edges = document.querySelectorAll('.edge');

    function highlight(id) {
        const n = document.getElementById(id);
        if (!n || id.includes('None')) return;
        n.classList.add('highlight');
        edges.forEach(e => { if (e.getAttribute('data-child-id') === id) e.classList.add('highlight'); });
        highlight(n.getAttribute('data-father'));
        highlight(n.getAttribute('data-mother'));
    }
    nodes.forEach(n => {
        n.addEventListener('mouseenter', () => {
            nodes.forEach(x => x.classList.add('dimmed'));
            edges.forEach(x => x.classList.add('dimmed'));
            highlight(n.id);
        });
        n.addEventListener('mouseleave', () => {
            nodes.forEach(x => x.classList.remove('dimmed', 'highlight'));
            edges.forEach(x => x.classList.remove('dimmed', 'highlight'));
        });
    });

    let scale = 1;
    let tx = 0;
    let ty = 0;

    function applyTransform() {
        container.setAttribute('transform', `translate(${tx} ${ty}) scale(${scale})`);
    }

    let dragging = false;
    let lastX = 0;
    let lastY = 0;

    svg.addEventListener('mousedown', (e) => {
        dragging = true;
        lastX = e.clientX;
        lastY = e.clientY;
    });

    window.addEventListener('mousemove', (e) => {
        if (!dragging) return;
        const dx = e.clientX - lastX;
        const dy = e.clientY - lastY;
        lastX = e.clientX;
        lastY = e.clientY;
        tx += dx;
        ty += dy;
        applyTransform();
    });

    window.addEventListener('mouseup', () => {
        dragging = false;
    });

    svg.addEventListener('wheel', (e) => {
        e.preventDefault();

        const rect = svg.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;

        const zoomFactor = (e.deltaY < 0) ? 1.03 : 1 / 1.03;
        const newScale = Math.min(3, Math.max(0.1, scale * zoomFactor));

        const k = newScale / scale;
        tx = mx - k * (mx - tx);
        ty = my - k * (my - ty);

        scale = newScale;
        applyTransform();
    }, { passive: false });

    nodes.forEach(n => {
        n.addEventListener('click', (e) => {
            if (e.target.closest('a')) return;

            const tr = n.getAttribute("transform");
            const m = /translate\(([-0-9.]+),\s*([-0-9.]+)\)/.exec(tr);
            if (!m) return;

            const nodeX = parseFloat(m[1]) + 192/2;
            const nodeY = parseFloat(m[2]) + 100/2;

            const rect = svg.getBoundingClientRect();
            const cx = rect.width / 2;
            const cy = rect.height / 2;

            tx = cx - nodeX * scale;
            ty = cy - nodeY * scale;

            applyTransform();
        });
    });

    applyTransform();
});
